int binarySearch(vector<int>& arr, int target) {
    int left = 0, right = arr.size(); // 注意右边界为n，表示可能插入位置
    while (left < right) {
        int mid = left + (right - left) / 2;
        if (arr[mid] >= target) {
            right = mid;          // 满足条件，缩小右边界
        } else {
            left = mid + 1;       // 不满足条件，缩小左边界
        }
    }
    return left; // 返回第一个>=target的位置，若不存在则返回arr.size()
}

