int binarySearchLastLE(vector<int>& arr, int target) {
    int left = -1, right = arr.size() - 1; // 左边界为-1，表示可能不存在
    while (left < right) {
        int mid = left + (right - left + 1) / 2; // 向上取整避免死循环
        if (arr[mid] <= target) {
            left = mid;          // 满足条件，扩大左边界
        } else {
            right = mid - 1;     // 不满足条件，缩小右边界
        }
    }
    return left; // 返回最后一个<=target的位置，若不存在则返回-1
}

